"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { LEVEL_LABELS, LEVEL_KEYS } from "@/lib/stats";

export default function Home() {
  const router = useRouter();
  const [search, setSearch] = useState("");

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (search.trim()) {
      router.push(`/players?q=${encodeURIComponent(search.trim())}`);
    }
  };

  return (
    <div className="max-w-2xl mx-auto py-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-10">
        <h1 className="text-3xl font-bold tracking-tight">Men&apos;s Basketball</h1>
        <select className="h-9 px-3 text-sm border border-slate-300 rounded-lg bg-white">
          <option>2025-26</option>
        </select>
      </div>

      {/* Entry points */}
      <div className="space-y-4 mb-10">
        <button
          onClick={() => router.push("/players")}
          className="w-full text-left bg-white border border-slate-200 rounded-xl px-6 py-5 hover:border-slate-400 hover:shadow-sm transition-all group"
        >
          <div className="text-lg font-semibold text-slate-900 group-hover:text-blue-600 transition-colors">
            All Players (National)
          </div>
          <div className="text-sm text-slate-500 mt-0.5">
            Every player in the database
          </div>
        </button>

        <button
          onClick={() => router.push("/teams")}
          className="w-full text-left bg-white border border-slate-200 rounded-xl px-6 py-5 hover:border-slate-400 hover:shadow-sm transition-all group"
        >
          <div className="text-lg font-semibold text-slate-900 group-hover:text-blue-600 transition-colors">
            All Teams
          </div>
          <div className="text-sm text-slate-500 mt-0.5">
            Every team in the database
          </div>
        </button>
      </div>

      {/* Levels grid */}
      <div className="mb-10">
        <h2 className="text-sm font-semibold text-slate-500 uppercase tracking-wide mb-3">
          Levels
        </h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
          {LEVEL_KEYS.map((key) => (
            <button
              key={key}
              onClick={() => router.push(`/players?level=${key}`)}
              className="bg-white border border-slate-200 rounded-lg px-4 py-3 text-sm font-medium text-slate-700 hover:border-slate-400 hover:text-blue-600 hover:shadow-sm transition-all"
            >
              {LEVEL_LABELS[key]}
            </button>
          ))}
        </div>
      </div>

      {/* Search */}
      <form onSubmit={handleSearch}>
        <input
          type="text"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search players..."
          className="w-full h-10 px-4 text-sm border border-slate-300 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        />
      </form>
    </div>
  );
}
